  payload = '{"species": "Orange", "species_slug": "orange", "varieties": [{"name": "Valencia", "slug": "valencia", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 0, "origin": "Developed by William Wolfskill in Santa Ana, California, mid-1800s from Portuguese stock", "traits": "Medium-large fruit, 2.7-3 inches diameter, smooth thin rind, bright orange when ripe", "flesh_fruit": "Deep orange, very juicy, sweet with slight tartness, excellent flavor. Few to many seeds", "yield_notes": "High productivity, holds well on tree for extended period", "growing_notes": "Ideal for humid subtropical climates subtropical climate. Main harvest December-June. Known as best juicing orange. Thrives in humid subtropical conditions. Crops exceptionally well in Queensland. Can carry two crops simultaneously", "availability": "Widely available from Queensland nurseries, Daley''s Fruit Nursery, local garden centers"}, {"name": "Seedless Valencia", "slug": "seedless-valencia", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 1, "origin": "Bud sport mutation of Valencia discovered in California", "traits": "Similar to Valencia, slightly earlier maturity, virtually seedless", "flesh_fruit": "Sweet, very juicy, excellent for fresh juice. No seeds to minimal seeds", "yield_notes": "Heavy cropper, reliable producer", "growing_notes": "", "availability": ""}, {"name": "Washington Navel", "slug": "washington-navel", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 2, "origin": "Brazil 1820s, brought to California 1873. One of oldest commercial navels, parent tree still producing in Riverside, California", "traits": "Large, round fruit with characteristic navel. Bright orange, thick pebbled rind, easy to peel", "flesh_fruit": "Sweet, low acid, excellent eating quality. Seedless. Easy to segment", "yield_notes": "Good producer but fruit should be used when ripe as prone to splitting in humid climates", "growing_notes": "", "availability": ""}, {"name": "Lane''s Late Navel", "slug": "lane-s-late-navel", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 3, "origin": "Australian selection, bud sport discovered in NSW", "traits": "Similar to Washington Navel, thin smooth rind. Fruit holds longer on tree", "flesh_fruit": "Sweet, seedless, excellent eating quality", "yield_notes": "Good cropper, extends navel season", "growing_notes": "Matures 2 months later than Washington (July-October). Great companion to Washington Navel for extended harvest. Popular in Southeast Queensland. Can store on tree up to 3 weeks longer than Washington", "availability": "Queensland nurseries, Daley''s Fruit, Burke''s Backyard recommended varieties"}, {"name": "Navelina", "slug": "navelina", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 4, "origin": "Spanish variety, early-maturing selection", "traits": "Large oblong fruit, excellent quality. Outstanding deep orange-red skin color, very attractive", "flesh_fruit": "Excellent quality, brilliant color, very early in season", "yield_notes": "Regular and good cropper in subtropical areas. Similar yields to Washington Navel", "growing_notes": "One of earliest navels to fruit. Naturally develops outstanding color. Performs excellently in humid subtropical climates subtropical conditions. Good fruit size", "availability": "Daley''s Fruit Nursery, specialized Queensland citrus suppliers"}, {"name": "Navelate", "slug": "navelate", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 5, "origin": "Spanish late-season navel variety", "traits": "Slightly oblong fruit, excellent flavor and rind texture. Can be slightly thorny when young", "flesh_fruit": "Excellent quality, consistent flavor", "yield_notes": "Consistent cropper", "growing_notes": "Matures same time as Washington but can store mature on tree about 3 weeks longer. Extends navel season in humid subtropical climates gardens", "availability": "Daley''s Fruit, select Queensland nurseries"}, {"name": "Arnold Blood Orange", "slug": "arnold-blood-orange", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 6, "origin": "Developed by Mike Arnold in South Australia, 1955. Sport of Moro blood orange", "traits": "Medium size, red-purple colored flesh and rind blush. Pebbled texture, somewhat difficult to peel", "flesh_fruit": "Deep red to maroon, sweet-tangy-tart with berry notes reminiscent of strawberries and raspberries. Sweet floral aroma. 9-11 segments", "yield_notes": "Good producer in subtropical areas", "growing_notes": "", "availability": ""}, {"name": "Cara Cara", "slug": "cara-cara", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 7, "origin": "Discovered 1976 at Hacienda Cara Cara in Valencia, Venezuela", "traits": "Navel variety, smaller than Washington Navel but similar appearance externally", "flesh_fruit": "Pink to red flesh similar to Star Ruby grapefruit. Very sweet, low acid. Seedless", "yield_notes": "Good producer, fruit often grows quite large", "growing_notes": "Does NOT need cold winter to develop color - ideal for humid subtropical climates and warmer Queensland areas. Matures slightly earlier than Washington Navel. Becoming very popular in Australia. Excellent eating orange with unique color", "availability": "Daley''s Fruit, Sunshine Citrus, specialized Queensland nurseries"}, {"name": "Joppa", "slug": "joppa", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 8, "origin": "Traditional variety, heavy mid-season bearer", "traits": "Medium fruit, traditional orange appearance", "flesh_fruit": "Very juicy, commercial juicing quality. Has seeds", "yield_notes": "Heavy fruit production in mid-season", "growing_notes": "Bears fruit AFTER Valencia crops finish, extending season. Recommended for Southeast Queensland with Valencia for 6 months of fruit. Commercial juicing variety adapted to home gardens", "availability": "Sunshine Citrus, select Queensland citrus specialists"}, {"name": "Hamlin", "slug": "hamlin", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 9, "origin": "Chance seedling near Glenwood, Florida 1879, named for owner A.G. Hamlin", "traits": "Small to medium, smooth thin poorly-colored peel. Round shape", "flesh_fruit": "Pale yellow juice, mild flavor, juicy. Nearly seedless (0-6 seeds)", "yield_notes": "High-yielding, cold-tolerant tree", "growing_notes": "", "availability": ""}, {"name": "Parson Brown", "slug": "parson-brown", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 10, "origin": "Florida heirloom, late 1800s. Most popular orange in Florida before modern varieties", "traits": "Slightly rough skin, early-season ripening", "flesh_fruit": "Sweet-tart flavor, high juice content, perfect for fresh juice", "yield_notes": "Good producer, early harvest", "growing_notes": "Florida heirloom variety with over 140 years history. Adapted to humid conditions. Some small growers still cultivate to preserve legacy. Early season variety for subtropical climates", "availability": "Rare in Australia, may need to source from specialty heirloom citrus collectors"}, {"name": "Pineapple Orange", "slug": "pineapple-orange", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 11, "origin": "Citra, Florida from seed 1860. Named for aromatic pineapple-like fragrance", "traits": "Medium size, 2.75-3 inches, slightly flattened ends. Smooth peel, can develop red-orange color in cool nights", "flesh_fruit": "Incredibly sweet and tropical flavor. Excellent juice color and quality. Seedy (15-25 seeds)", "yield_notes": "Good production December-February", "growing_notes": "Florida heirloom 160+ years old. Intense sweetness and fragrant aroma. Thin skin made it unsuitable for long-distance shipping, leading to decline. Rare heritage variety worth preserving. Mid-season harvest", "availability": "Rare, specialty Florida heirloom collectors, limited availability Australia"}, {"name": "Tarocco", "slug": "tarocco", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 12, "origin": "Italian blood orange variety from Sicily", "traits": "Very large fruit, excellent appearance", "flesh_fruit": "Great flavor, blood orange characteristics", "yield_notes": "Slow to come into production but productive once established", "growing_notes": "Can be grown in humid subtropical climates but Arnold Blood is more reliable for subtropical conditions. Requires Mediterranean-like climate ideally but some success in Queensland with proper care", "availability": "Victorian Citrus Farms, Yalca Fruit Trees, select Australian nurseries"}, {"name": "Moro", "slug": "moro", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 13, "origin": "Italian variety, most pigmented blood orange", "traits": "Medium to large, deep red interior and exterior blush", "flesh_fruit": "Most intensely colored blood orange, sweet-tart flavor", "yield_notes": "Good production in suitable climates", "growing_notes": "", "availability": ""}, {"name": "Bergamot (Sour Orange)", "slug": "bergamot-sour-orange", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 14, "origin": "Southern Italy, heritage variety. Also known as Castagnaro", "traits": "Most fragrant of all citrus. Small tree, attractive", "flesh_fruit": "Sour flesh, not for eating fresh. Used in marmalades and baking", "yield_notes": "Good ornamental and productive for rind use", "growing_notes": "Rind oil used in Earl Grey Tea, Turkish Delight, health products, cosmetics. More frost hardy than other citrus. Wonderful small ornamental tree. Traditional heritage variety with cultural significance", "availability": "Daley''s Fruit Nursery, specialty Queensland citrus suppliers"}, {"name": "Seville (Bitter Orange)", "slug": "seville-bitter-orange", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 15, "origin": "Southeast Asia, spread to Europe via Moorish Spain. Named after Seville, Spain", "traits": "Medium fruit, bitter flavor, traditional marmalade orange", "flesh_fruit": "Sour and bitter, pairs well with sugar sweetness", "yield_notes": "Hardy, vigorous, more frost hardy than other citrus", "growing_notes": "", "availability": ""}, {"name": "Nagpur Orange (Santra) 🏆", "slug": "nagpur-orange-santra", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 0, "origin": "Nagpur, Maharashtra, India. Indigenous to India, also called Nagpur Mandarin or Ponkan type", "traits": "Large loose-jacket mandarin, 134-150g, 60-70mm diameter. Medium-thick rind, orange-colored, prominent sunken oil glands", "flesh_fruit": "Orange flesh, tender, melting, very juicy (45% juice), mild and pleasant aromatic flavor. 8-10 segments, 18-20 seeds. Sweet with 0.6-0.7% citric acid", "yield_notes": "Productive but alternate bearing tendency. Peak production 10-20 years", "growing_notes": "ONE OF THE BEST MANDARINS IN THE WORLD. Geographic Indication status (GI tag) 2014. Perfect for tropical monsoon. Blossoms during monsoon, matures February-March (Mrig crop) for export. India''s most famous orange. Climatically one of most tropical mandarins. Performs excellently in tropical monsoon climates conditions", "availability": "Greens of tropical monsoon climates, widespread availability in tropical monsoon climates nurseries, Maharashtra suppliers"}, {"name": "Coorg Orange (Kodagu Orange) 🏆", "slug": "coorg-orange-kodagu-orange", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 1, "origin": "Coorg (Kodagu), Karnataka, India. Believed introduced from Central India 300 years ago. GI status 2006", "traits": "Greenish-yellow color, medium size (smaller than Nagpur), tight skin, well-blended sugar-acid content. Mandarin hybrid (Citrus reticulata)", "flesh_fruit": "Sweet-sour taste, deliciously juicy, rich orange pulp, distinctive sweet-tangy flavor", "yield_notes": "Good yield under proper conditions", "growing_notes": "", "availability": ""}, {"name": "Khasi Mandarin (Soh Niamtra) 🏆", "slug": "khasi-mandarin-soh-niamtra", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 2, "origin": "Meghalaya, Northeast India (Khasi, Jaintia hills). Indigenous to Indo-Burma biodiversity hotspot. GI tag", "traits": "Slightly bigger than tennis ball, 134-150g, 60-70mm diameter. Smooth TIGHT skin (harder to peel than other mandarins), orange-yellow to bright orange, 3-3.5mm thick peel", "flesh_fruit": "More flesh and juice than other mandarins. Sweet, aromatic, distinctive quality. Vibrant golden color. 45% juiciness, 0.6-0.7% citric acid - one of sweetest oranges. 8-10 segments", "yield_notes": "Makes up 43.6% of India''s total citrus production. 38.2% of citrus orchard area", "growing_notes": "INDIA''S PRIMARY CITRUS. Indigenous to Northeast. Called ''King of Oranges''. Primary gene center for world''s Citrus species. Harvest November-late February/April. Traditional bamboo harvesting tool (proh). Perfect for monsoon regions. Can grow in tropical monsoon climates with similar conditions. Cultural significance to Khasi and Jaintia people", "availability": "Northeast India nurseries, may be available tropical monsoon climates through specialized suppliers"}, {"name": "Sikkim Mandarin 🏆", "slug": "sikkim-mandarin", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 3, "origin": "Sikkim, India. Native to Himalayan foothills. Closely related to Khasi and Coorg mandarins", "traits": "Similar to other Indian mandarins, adapted to mountain/hill conditions", "flesh_fruit": "Sweet, juicy, known for excellent quality and taste", "yield_notes": "Good production in hill areas 600-1500m elevation", "growing_notes": "Indigenous to India. Nucellar clonal budline of Nagpur. Popular in Kolkata markets. Grows in Tista and Rangeet valleys. Could adapt to tropical monsoon climates hill regions like Munnar, Wayanad", "availability": "Sikkim state nurseries, Northeast suppliers"}, {"name": "Assam Mandarin 🏆", "slug": "assam-mandarin", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 4, "origin": "Assam, Northeast India. Indigenous variety", "traits": "Seedling variety, nucellar clonal budline of Nagpur", "flesh_fruit": "Sweet, juicy, typical mandarin characteristics", "yield_notes": "Good production in Brahmaputra valley and Dibrugarh districts", "growing_notes": "Indigenous to India''s Northeast. Adapted to monsoon climate. Could perform in tropical monsoon climates tropical monsoon conditions. Part of India''s traditional orange heritage", "availability": "Assam state nurseries, Northeast India suppliers"}, {"name": "Kinnow", "slug": "kinnow", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "sort_order": 5, "origin": "Hybrid of King mandarin and Willow Leaf mandarin, developed in California but widely adopted in India", "traits": "Glossy skin, attractive appearance, medium size", "flesh_fruit": "Tangy-sweet taste, very juicy, excellent for juice", "yield_notes": "High-yielding variety, very productive", "growing_notes": "Very popular in Punjab and Northern India. Grown successfully in Northeast states including areas near tropical monsoon climates. Adapts to warm climates. Harvest mid-January to mid-February. TSS:Acid ratio 12:1 at maturity", "availability": "Widely available Indian nurseries, tropical monsoon climates suppliers"}, {"name": "Mosambi (Sweet Lime, Bathayi) 🌱", "slug": "mosambi-sweet-lime-bathayi", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 6, "origin": "Native to Southern Iran, Southeast Asia. Widely cultivated throughout India. Called ''bathayi'' in tropical monsoon climates Malayalam", "traits": "Small tree up to 8m. Oval fruit, green ripening to yellow-green, greenish pulp. Smooth to slightly rough skin. Not a true orange but Citrus limetta", "flesh_fruit": "Sweet and mild flavor (essence of lime without tartness). 50mg Vitamin C per 100g. Juice turns bitter quickly in air", "yield_notes": "Begins bearing 5-7 years, peak 10-20 years", "growing_notes": "PERFECT FOR tropical monsoon climates TROPICAL CLIMATE. Most common citrus juice in Indian subcontinent. Refreshing in hot weather. Thrives in tropical and subtropical climates. Popular at mobile road stalls. Rich in antioxidants. Traditional Indian fruit. Maharashtra, Andhra Pradesh, Punjab top producers", "availability": "Greens of tropical monsoon climates, widespread tropical monsoon climates availability, all India nurseries"}, {"name": "Hamlin", "slug": "hamlin", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 7, "origin": "Florida 1879 - same as humid subtropical climates listing", "traits": "Small to medium, smooth thin peel. 2.75-3 inch diameter", "flesh_fruit": "Pale yellow juice, mild, juicy, 0-6 seeds", "yield_notes": "High-yielding, cold-tolerant", "growing_notes": "EXCELLENT for Tropical monsoon tropical monsoon climate. Specifically noted as producing satisfactory size fruit in SEMITROPICAL CLIMATES with HIGH HEAT AND HUMIDITY - perfect description of tropical monsoon climates! Early season October-December. Orange trees produce earlier in humid tropics than subtropics", "availability": "May need to source internationally, Florida varieties increasingly available India"}, {"name": "Valencia", "slug": "valencia", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 8, "origin": "California mid-1800s (same as humid subtropical climates listing)", "traits": "Medium-large, smooth thin rind, bright orange", "flesh_fruit": "Sweet, juicy, excellent for juice. Few to many seeds", "yield_notes": "High, holds well on tree", "growing_notes": "Popular in India. Grown in North and South India including Tamil Nadu. Available in tropical monsoon climates markets. Summer orange (November-February season in India). Thrives in warm climates zones 9-11. Can handle tropical conditions if humidity managed properly", "availability": "Indian nurseries, may be available tropical monsoon climates through citrus specialists"}, {"name": "Darjeeling Orange 🏆", "slug": "darjeeling-orange", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 9, "origin": "Darjeeling, West Bengal hill regions. Indigenous to India", "traits": "Specialty variety, thin peel", "flesh_fruit": "Unique sweetness and fragrance, high juice content", "yield_notes": "Good production in hilly regions", "growing_notes": "", "availability": ""}, {"name": "Madhura Naranga (Sweet Orange)", "slug": "madhura-naranga-sweet-orange", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 10, "origin": "", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}, {"name": "Mudkhed Orange 🌱", "slug": "mudkhed-orange", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 11, "origin": "Mudkhed area, Maharashtra, India", "traits": "Medium size, bright orange color", "flesh_fruit": "Tender, juicy, sweet flavor", "yield_notes": "Good production", "growing_notes": "Popular in Maharashtra alongside Nagpur oranges. Regional specialty. Can be used for juice or fresh eating. Indigenous to Maharashtra region", "availability": "Maharashtra nurseries, may be sourced to tropical monsoon climates"}, {"name": "Sathgudi Orange 🌱", "slug": "sathgudi-orange", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 12, "origin": "Andhra Pradesh and Tamil Nadu, South India", "traits": "Smooth skin, attractive appearance", "flesh_fruit": "Sweet taste, high juice content", "yield_notes": "Popular commercial variety in South India", "growing_notes": "", "availability": ""}, {"name": "Tangor (Orange-Mandarin Hybrids)", "slug": "tangor-orange-mandarin-hybrids", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "sort_order": 13, "origin": "Various hybrids between sweet oranges and mandarins", "traits": "Characteristics intermediate between oranges and mandarins", "flesh_fruit": "Usually sweet, sometimes easier to peel than oranges", "yield_notes": "Variable depending on specific variety", "growing_notes": "Various tangor types grown in India. Ellendale is example of tangor. Adapted to tropical and subtropical conditions. Available through Indian citrus programs", "availability": "Various Indian nurseries"}, {"name": "Blood Orange (Various)", "slug": "blood-orange-various", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 14, "origin": "Various blood orange varieties, originally Mediterranean", "traits": "Distinctive deep red flesh due to anthocyanin pigments", "flesh_fruit": "Sweet with berry-like flavor, red to burgundy interior", "yield_notes": "Variable, generally needs cool nights for color", "growing_notes": "", "availability": ""}], "variety_count": 31}'::jsonb,
