-- Parsnip (18 cultivars)
UPDATE public.garden_import_queue SET
  payload = '{"species": "Parsnip", "species_slug": "parsnip", "varieties": [{"name": "Hollow Crown", "slug": "hollow-crown", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 0, "origin": "England, 1820s or earlier | Days to maturity: 100-130 days", "traits": "Long, tapered white roots 25-40cm (10-16 inches). Cream-colored skin, smooth texture. Crown slightly sinks inward (hollow-crowned). Foliage tends to sprawl rather than grow upright.", "flesh_fruit": "Exceptionally sweet and buttery flavor. Fine-grained, smooth texture when cooked. Sweet without acidity. Minimal core. Excellent for mashing, roasting, and soups.", "yield_notes": "High and reliable, even in difficult years. Consistent performer across various conditions.", "growing_notes": "", "availability": "The Seed Collection Australia, Mr Fothergill''s Seeds, Greenpatch Organic Seeds, Eden Seeds, Australian seed merchants"}, {"name": "The Student (Sutton''s Student)", "slug": "the-student-sutton-s-student", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 1, "origin": "England, 1859 - bred by James Buckman at Royal Agricultural College from wild parsnip | Days: 150 days", "traits": "Short to medium length, never more than 15 inches (38cm). Wedge-shaped root with quick taper. Wide shoulders. Smooth skin with little to no splitting. Less hairy foliage (bred to reduce skin irritation from plant sap).", "flesh_fruit": "Slightly sweet and mellow flavor. Consistent quality. Fine-grained texture. Excellent for roasting and adding to vegetable mixes.", "yield_notes": "Consistent and reliable. Least likely of all varieties to deteriorate in storage. Produces well even in less-than-ideal conditions.", "growing_notes": "", "availability": ""}, {"name": "Guernsey (Panais Long)", "slug": "guernsey-panais-long", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 2, "origin": "France, introduced to England 1826, pre-1826 French variety | Days: 120 days", "traits": "Shorter than many modern varieties (half-long type). Broad shoulders taper to point. Attractive smooth white skin. Stumpy roots easier to harvest. Considered ''Guernsey Half Long'' due to shorter length.", "flesh_fruit": "Superior flavor - farmers in Guernsey consider it the most nutritious root vegetable, superior to carrots and potatoes. Sweet and flavorful. Excellent roasting variety.", "yield_notes": "Good yields even without hybrid vigor. Reliable cropper. Traditional favorite in Guernsey for generations.", "growing_notes": "", "availability": ""}, {"name": "Harris Model (Harris Early Model)", "slug": "harris-model-harris-early-model", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 3, "origin": "United States, 1897 | Days: 110-130 days", "traits": "Smooth white skin, straight tapered roots 10-15 inches (25-38cm) long. Nearly solid crown (minimal hollow crown). Very few side roots. Uniform shape. Finely grained flesh. Roots about 3.5 inches diameter at shoulders.", "flesh_fruit": "Sweet-flavored. White and tender. Fine-grained texture. Flavor improves after frost. Good for roasting, mashing, soups.", "yield_notes": "Consistently high yields. Easy to pull due to few side roots. Popular with both home gardeners and commercial growers. Workhorse variety.", "growing_notes": "", "availability": "Fedco Seeds, Victory Seeds, Sandhill Preservation, Australian seed merchants, The Seed Collection, Mr Fothergill''s"}, {"name": "All American", "slug": "all-american", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 4, "origin": "United States | Days: 95 days (fast-maturing)", "traits": "Long, tapered roots with creamy-white color. Fast-growing variety. Smooth skin. High sugar content. Vigorous growth capability.", "flesh_fruit": "Sweet and nutty flavor. Tender texture. Excellent for roasting, soups, and stews. Rich taste from high sugar content.", "yield_notes": "High yields. Strong resistance to disease and pests. Generous harvests with proper care. Stores well.", "growing_notes": "", "availability": ""}, {"name": "Cobham Marrow (Cobham Improved)", "slug": "cobham-marrow-cobham-improved", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 5, "origin": "England | Days: 120 days", "traits": "Short roots up to 8 inches (20cm) long. Broader and stubbier than most varieties. White skin. Good germination rate (germinates within 3 weeks). Highly resistant to canker disease.", "flesh_fruit": "One of the SWEETEST parsnip varieties available. Exceptional sweetness. Most often used in desserts or glazed with brown sugar. Tender texture. Sweet flavor develops further after first frosts.", "yield_notes": "Good yields for a short-rooted variety. Reliable cropper. Harvest-ready in 120 days.", "growing_notes": "", "availability": ""}, {"name": "Gladiator F1", "slug": "gladiator-f1", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 6, "origin": "England, 1982 - first F1 hybrid parsnip (Tozer Seeds) | Days: 120 days", "traits": "Long, smooth white roots. Slender wedge-shaped. Shallow crowns for easy cleaning. Uniform shape and size. Sets the standard for modern F1 parsnips. Bred for commercial and show bench quality.", "flesh_fruit": "Sweet, earthy flavor. Smooth skin and flesh. Excellent eating quality. Good for exhibition and everyday use.", "yield_notes": "High and consistent yields. Excellent canker resistance. Strong disease resistance overall. Tremendous field holding capacity. Can be cropped almost continuously from July onwards.", "growing_notes": "", "availability": ""}, {"name": "Javelin F1", "slug": "javelin-f1", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 7, "origin": "UK, Tozer Seeds (post-Gladiator development) | Days: 110-130 days", "traits": "Slim, smooth, tapered roots. Narrower than Albion. Shallow crown for easy cleaning. Long straight roots typically 27cm. Consistent performer. Ideal for pre-pack market. Holds size longer in field.", "flesh_fruit": "Sweet flavor. High dry matter content. Good eating quality. Suitable for fresh market and processing.", "yield_notes": "Consistent high yields. Excellent for overwintering. Strong field resistance to canker. Reliable performer across varying conditions. Popular with commercial growers globally.", "growing_notes": "", "availability": ""}, {"name": "Albion F1", "slug": "albion-f1", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 8, "origin": "UK, Tozer Seeds | Days: 120 days", "traits": "Very white skin finish - noticeably slower to discolor than other varieties. Obovate root shape tapering nicely. Long tapered roots fill well down root length. Big and chunky. Attractive appearance. RHS Award of Garden Merit (2009, reconfirmed 2013).", "flesh_fruit": "Excellent sweet taste. Very sweet to taste. Smooth texture. High quality for fresh eating.", "yield_notes": "Heavy weight yields. High-yielding variety. Very resistant to many diseases including canker. Suitable for retail trade and processing. Suitable for early/main season sowing.", "growing_notes": "", "availability": ""}, {"name": "Tender and True", "slug": "tender-and-true", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 9, "origin": "England, early 1800s | Days: 130 days", "traits": "Long tapered roots. Pale white skin. Consistent type. Minimal core - virtually coreless. Particularly straight roots. Good for show bench and kitchen use.", "flesh_fruit": "Very sweet flavor - exceptional sweetness. Creamy taste. Particularly tender due to minimal core. Smooth texture. Many experts consider this the best-tasting parsnip variety.", "yield_notes": "Good resistance to canker. Produces handsome roots in ideal conditions. Reliable cropper in proper conditions. Not suited to heavy soils - requires lighter soil for best results.", "growing_notes": "", "availability": ""}, {"name": "Lancer", "slug": "lancer", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 10, "origin": "Modern variety (newer release) | Days: 120 days", "traits": "Long roots. Smooth, evenly colored skin. Clean appearance. Uniform shape and size. Developed for market growers.", "flesh_fruit": "Delicate taste. Cream-colored flesh. Good eating quality. Appeals to wide range of palates.", "yield_notes": "Productive choice for market growers. EXCEPTIONAL resistance to canker - best-in-class disease resistance. High yields with proper care. Commercial-quality production.", "growing_notes": "", "availability": ""}, {"name": "Andover", "slug": "andover", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 11, "origin": "Modern variety (recent release) | Days: 120 days", "traits": "Open-pollinated variety. Good uniformity for non-hybrid. Standard parsnip appearance. Clean roots.", "flesh_fruit": "Good flavor. Standard parsnip taste. Suitable for general cooking uses.", "yield_notes": "Good yields. RESISTANT to canker disease - specifically bred for canker resistance. Reliable production.", "growing_notes": "", "availability": ""}, {"name": "White Gem", "slug": "white-gem", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 12, "origin": "UK variety | Days: 120 days", "traits": "Short-rooted and broad shouldered. Medium length. Smooth-skinned. High quality appearance. Suitable for almost all soil types due to shorter roots.", "flesh_fruit": "Fine flavor. Good eating quality.", "yield_notes": "HIGH YIELDER. One of most popular and reliable varieties. Good canker resistance. Delivers lots of fine, high-quality parsnips.", "growing_notes": "", "availability": ""}, {"name": "Turga (Halblange Turga)", "slug": "turga-halblange-turga", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 13, "origin": "Hungary (Hungarian heirloom) | Days: 100-110 days", "traits": "Short to medium roots 5-7 inches (13-18cm) long. Stout and broad. Smooth white skin. Wide at top with minimal taper. Uniform appearance. Improvement on Guernsey parsnip. Selected for generations for minimal taper and no forking.", "flesh_fruit": "Flavorful and sweet. Sweet, coconut-like flavor. Tender texture. Young leaves edible in salads, mature leaves good for soup.", "yield_notes": "Heavy yielding. Large diameter for a short variety. Workhorse parsnip. Good for heavy clay soils.", "growing_notes": "", "availability": "Southern Exposure Seed Exchange, Kokopelli Seeds, Siskiyou Seeds, European seed houses, specialty heirloom suppliers"}, {"name": "Panorama F1", "slug": "panorama-f1", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 14, "origin": "Modern F1 hybrid | Days: 120 days", "traits": "Long roots. Vigorous variety. Strong growing habit. Good uniformity.", "flesh_fruit": "Great sweet flavor. Excellent eating quality.", "yield_notes": "Vigorous growth produces good yields. Reliable cropper.", "growing_notes": "", "availability": "Thompson & Morgan, UK seed suppliers, some Australian seed merchants"}, {"name": "Countess F1", "slug": "countess-f1", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 15, "origin": "Modern F1 hybrid, Tozer Seeds | Days: 110-120 days", "traits": "Long, smooth-skinned roots. Uniform shape and size. High quality appearance. Shorter-rooted than Gladiator or Javelin.", "flesh_fruit": "Good flavor. Quality eating.", "yield_notes": "HIGH-YIELDING variety. Uniform production. Consistent results.", "growing_notes": "", "availability": ""}, {"name": "Warrior F1", "slug": "warrior-f1", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 16, "origin": "Modern F1 hybrid, Tozer Seeds (recent release) | Days: 110 days (early maturity)", "traits": "Attractive white root. Carries weight well down length of root. Early vigor variety. Heavier, whiter skin than older varieties. Improved root shape. Consistent product for roasting.", "flesh_fruit": "Good flavor. Quality flesh throughout length of root.", "yield_notes": "Higher yield - more consistent product. Weight distributed well along root gives better usable yield.", "growing_notes": "", "availability": ""}, {"name": "Viking", "slug": "viking", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 17, "origin": "Modern variety, Tozer Seeds (recent release) | Days: 110 days (early maturity)", "traits": "Long roots, slender wedge-shaped. Well-filled roots typically 27cm. Vigorous foliage. Early maturing line. Whiter skin than some varieties. Holds weight down root for consistency.", "flesh_fruit": "Good flavor. Consistent quality for roasting.", "yield_notes": "Higher yield due to weight distribution. More consistent product. Good commercial potential.", "growing_notes": "", "availability": ""}], "variety_count": 18}'::jsonb,
  variety_count = 18
WHERE species_slug = 'parsnip'
   OR source_path = 'brainstorm-inbox/import-payloads/parsnip.json';

